import {EncodingType, ServeFiles, fileType} from '../types';

export const ENC_UTF8 = 'utf-8';
export const ENC_BASE64 = 'base64';

/**
 * @typedef ProviderFile
 * @property {string} path - file path relative to the container
 * @property {string} content - file content
 * @property {string} encoding - content encoding (utf-8, base64)
 */

export class Provider {
  files: fileType[];

  constructor() {
    /** @type {Array<ProviderFile>} */
    this.files = [];
  }

  addFile(path, content, encoding: EncodingType) {
    this.files.push({
      path,
      content,
      encoding,
    });
  }

  clearFiles() {
    this.files = [];
  }

  async serveFiles(
    _option?: ServeFiles | any,
  ): Promise<
    | void
    | string
    | string
    | Array<number>
    | Uint8Array
    | ArrayBuffer
    | Blob
    | Buffer
  > {
    if (this.files.length === 0) {
      throw new Error('No files to serve');
    }
  }
}
